import React from 'react';
import { useBlockchain } from '../context/BlockchainContext';
import { Link } from 'react-router-dom';

const Navbar: React.FC = () => {
  const { account, connectWallet, disconnectWallet, isAdmin, isVerifier } = useBlockchain();

  return (
    <nav style={{ display: 'flex', justifyContent: 'space-between', padding: '1rem', backgroundColor: '#282c34', color: 'white' }}>
      <div style={{ display: 'flex', gap: '1rem', alignItems: 'center' }}>
        <h2 style={{ margin: 0 }}>DeKYC</h2>
        <Link to="/" style={{ color: 'white', textDecoration: 'none' }}>Home</Link>
        {account && <Link to="/user" style={{ color: 'white', textDecoration: 'none' }}>User Dashboard</Link>}
        {isVerifier && <Link to="/verifier" style={{ color: 'white', textDecoration: 'none' }}>Verifier Dashboard</Link>}
        {isAdmin && <Link to="/admin" style={{ color: 'white', textDecoration: 'none' }}>Admin Dashboard</Link>}
      </div>
      <div>
        {account ? (
          <div style={{ display: 'flex', gap: '1rem', alignItems: 'center' }}>
            <span>{account.slice(0, 6)}...{account.slice(-4)}</span>
            <button onClick={disconnectWallet} style={{ padding: '0.5rem 1rem', cursor: 'pointer' }}>Disconnect</button>
          </div>
        ) : (
          <button onClick={connectWallet} style={{ padding: '0.5rem 1rem', cursor: 'pointer', backgroundColor: '#61dafb', border: 'none', borderRadius: '4px' }}>
            Connect Wallet
          </button>
        )}
      </div>
    </nav>
  );
};

export default Navbar;
